/* =========================================
   auth.css — Login / Register Modal
   เข้าธีม Drink or Doom (ดำ / แดง / ทอง)
   ========================================= */

/* ---- OVERLAY ---- */
#login-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,.92);
  z-index: 600;
  display: none; align-items: center; justify-content: center;
  backdrop-filter: blur(8px);
}
#login-overlay.show { display: flex; }

/* ---- MODAL BOX ---- */
.login-box {
  background: linear-gradient(145deg, #181818, #101010);
  border: 1px solid #272727;
  border-radius: 20px;
  padding: 38px 38px 32px;
  max-width: 420px; width: 92%;
  position: relative;
  box-shadow: 0 0 80px rgba(229,9,20,.15), 0 30px 80px rgba(0,0,0,.8);
  animation: authSlideUp .35s cubic-bezier(.23,1,.32,1);
}
/* เส้นแดงบน */
.login-box::before {
  content: "";
  position: absolute; top: 0; left: 0; right: 0; height: 2px;
  background: linear-gradient(90deg, transparent, var(--red), transparent);
  border-radius: 20px 20px 0 0;
}

@keyframes authSlideUp {
  from { transform: translateY(32px) scale(.96); opacity: 0; }
  to   { transform: translateY(0) scale(1);      opacity: 1; }
}

/* ---- LOGO ในmodal ---- */
.auth-logo {
  text-align: center;
  margin-bottom: 22px;
}
.auth-logo .logo-main {
  font-family: "Kanit", sans-serif;
  font-weight: 900; font-size: 2rem;
  color: var(--red);
  letter-spacing: -0.5px;
  text-shadow: 0 0 20px rgba(229,9,20,.6), 0 2px 4px rgba(0,0,0,.8);
}
.auth-logo .logo-sub {
  font-family: "Kanit", sans-serif;
  font-weight: 300; font-size: .55rem;
  color: var(--text2); letter-spacing: 3.5px;
  display: block; margin-top: 2px;
}

/* ---- TAB TOGGLE ---- */
.login-tabs {
  display: flex;
  background: #111;
  border: 1px solid #1e1e1e;
  border-radius: 10px;
  padding: 3px; gap: 3px;
  margin-bottom: 24px;
}
.login-tab {
  flex: 1; padding: 9px 0;
  border-radius: 7px; border: none;
  background: transparent; color: var(--text2);
  font-family: "Kanit", sans-serif; font-weight: 600; font-size: .88rem;
  cursor: pointer; transition: .2s;
}
.login-tab.act {
  background: var(--red); color: #fff;
}

/* ---- MODAL TITLE ---- */
.auth-ttl {
  font-family: "Kanit", sans-serif;
  font-weight: 900; font-size: 1.55rem;
  letter-spacing: 2px;
  margin-bottom: 20px;
  display: flex; align-items: center; gap: 10px;
}
.auth-ttl .r { color: var(--red); }

/* ---- FORM FIELDS (ใช้ .fg และ .fc จาก admin.css) ---- */

/* ---- ERROR MESSAGE ---- */
.login-err {
  min-height: 20px;
  font-size: .82rem;
  color: var(--red);
  margin-bottom: 10px;
  display: flex; align-items: center; gap: 6px;
}
.login-err:not(:empty)::before {
  content: "\f071"; /* fa warning icon — ใช้ text แทน */
  font-family: inherit;
}

/* ---- AUTH BUTTON ---- */
.btn-auth {
  width: 100%; padding: 13px;
  background: var(--red); color: #fff; border: none;
  border-radius: 8px;
  font-family: "Kanit", sans-serif; font-weight: 700; font-size: 1rem;
  cursor: pointer; transition: .2s;
  display: flex; align-items: center; justify-content: center; gap: 8px;
  margin-top: 4px;
}
.btn-auth:hover:not(:disabled) {
  background: var(--red3);
  box-shadow: 0 4px 20px var(--glow);
  transform: translateY(-1px);
}
.btn-auth:disabled {
  opacity: .6; cursor: not-allowed;
}

/* ---- USER CHIP ใน Header ---- */
.user-chip {
  display: none; /* JS จะเปิด */
  align-items: center; gap: 8px;
  background: linear-gradient(135deg, #1a0505, #2d0808);
  border: 1px solid var(--red2); border-radius: 30px;
  padding: 6px 14px 6px 10px;
  box-shadow: 0 0 14px rgba(229,9,20,.1);
}
.user-chip i {
  color: var(--red); font-size: .9rem;
}
.user-chip #user-display-name {
  color: #fff; font-weight: 700; font-size: .85rem;
  max-width: 100px;
  overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
}
/* ปุ่ม logout ใน chip */
.user-chip .btn-ghost {
  padding: 4px 8px; font-size: .78rem;
  border-color: rgba(229,9,20,.25);
  color: var(--text2);
}
.user-chip .btn-ghost:hover {
  border-color: var(--red); color: var(--red);
  background: rgba(229,9,20,.08);
}

/* ---- ปุ่ม Login ใน Header ---- */
#btn-login {
  display: flex; /* JS จะซ่อน/แสดง */
  align-items: center; gap: 6px;
  background: transparent;
  border: 1px solid rgba(229,9,20,.4);
  color: var(--text2);
  padding: 7px 14px; border-radius: 6px;
  font-family: "Kanit", sans-serif; font-size: .82rem;
  cursor: pointer; transition: .2s;
  white-space: nowrap;
}
#btn-login:hover {
  border-color: var(--red); color: #fff;
  background: rgba(229,9,20,.08);
}

/* ---- RESPONSIVE ---- */
@media (max-width: 580px) {
  .login-box { padding: 28px 20px 24px; }
  .auth-ttl  { font-size: 1.3rem; }
  #btn-login .lbl-txt { display: none; }
  .user-chip #user-display-name { max-width: 70px; }
}

/* ---- SPIN ANIMATION สำหรับ loading ---- */
@keyframes spin {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}
.fi-spin { animation: spin .7s linear infinite; display: inline-block; }
